CREATE DATABASE Healthcare_Medical_Recruitment;

USE Healthcare_Medical_Recruitment;

CREATE TABLE Jobs (
    Job_Id INT PRIMARY KEY,
    Institution_Name VARCHAR(120) NOT NULL,
    Job_Type VARCHAR(20) NOT NULL,
    Department VARCHAR(100) NOT NULL,
    Job_Role VARCHAR(50) NOT NULL,
    Specialization VARCHAR(100) NOT NULL,
    Location VARCHAR(80) NOT NULL,
    Posted_Date DATE NOT NULL,
    Vacancy_Count INT NOT NULL,
    Status VARCHAR(20) NOT NULL
);


CREATE TABLE Candidates (
    Candidate_name        VARCHAR(100) NOT NULL,
    Phone                 VARCHAR(15),
    Email                 VARCHAR(100) NOT NULL,
    City                  VARCHAR(50),
    Preferred_Location    VARCHAR(70),
    Qualification         VARCHAR(100) NOT NULL,
    Specialization        VARCHAR(100) NOT NULL,
    Experience_years      INT          NOT NULL,
    Source                VARCHAR(50)  NOT NULL,
    Target_institution    VARCHAR(100)  NOT NULL,
    Current_position      VARCHAR(70)  NOT NULL,
    SR_years              INT          NOT NULL DEFAULT 0,
    Ap_years              INT          NOT NULL DEFAULT 0,
    Assoc_prof_years      INT          NOT NULL DEFAULT 0,
    Status_of_BCBR_MET    VARCHAR(10)  NOT NULL DEFAULT 'No',
    CONSTRAINT PK_Candidates PRIMARY KEY (Candidate_name, Email)
);






CREATE TABLE Applications (
    Job_Id                    INT NULL,
    Application_id            INT IDENTITY(1,1) NOT NULL,
    Candidate_name            VARCHAR(100) NOT NULL,
    Email                     VARCHAR(100) NOT NULL,
    Applied_date              DATE NOT NULL,
    Current_role              VARCHAR(100) NOT NULL,
    Current_salary_package    DECIMAL(10,2) NOT NULL,
    Job_role                  VARCHAR(100) NOT NULL,
    Expected_salary_package   DECIMAL(10,2) NOT NULL,
    Job_type                  VARCHAR(20) NOT NULL,
    Application_status        VARCHAR(30) NOT NULL,
    Offer_from                VARCHAR(100) NULL,
    Offered_locations         VARCHAR(200) NULL,
    Hired_at                  VARCHAR(100) NULL,
    Hired_location            VARCHAR(100) NULL,
    Current_location          VARCHAR(50) NULL,
    Preferred_location        VARCHAR(50) NULL,
    Offered_salary_package    DECIMAL(10,2) NULL,
    Final_salary_package      DECIMAL(10,2) NULL,
    Exam_status               VARCHAR(10) NOT NULL,
    CONSTRAINT PK_Applications PRIMARY KEY (Application_id),
    CONSTRAINT FK_Applications_Jobs FOREIGN KEY (Job_Id) REFERENCES Jobs (Job_Id)
    );


